import type {
  ItemPropertiesApplication,
  ItemPropertiesDocumentSystem,
  ItemPropertyContext,
} from "./types";

import {
  WOUNDING_TYPE_LABELS,
  WOUNDING_TYPE_QUALITY_KEYS,
} from "../../../functions/critical-hits/damage-categories";
import { WOUNDING_TYPES, type WoundingType } from "../../../types/critical-hits";
import { asArray, asRecord } from "../runtime-values";

export const WOUNDING_SECTION_CLASS = "ech-wounding-properties";
export const WOUNDING_QUALITY_KEYS = new Set<string>(Object.values(WOUNDING_TYPE_QUALITY_KEYS));

export function appendWoundingLabels(qualities: Record<string, string>): Record<string, string> {
  const labels = { ...qualities };

  for (const woundingType of WOUNDING_TYPES) {
    labels[WOUNDING_TYPE_QUALITY_KEYS[woundingType]] = WOUNDING_TYPE_LABELS[woundingType];
  }

  return labels;
}

export function supportsDamageTypeProperties(
  document: ItemPropertiesApplication["document"],
): boolean {
  return supportsWeaponProperties(document) || supportsDamagingMagicProperties(document);
}

export function supportsStandaloneDamageTypeRow(
  document: ItemPropertiesApplication["document"],
): boolean {
  return document?.type === "spell" || document?.type === "prayer";
}

export function getDamageTypeLabelsFromDocument(
  document: ItemPropertiesApplication["document"],
): string[] {
  const system = asRecord(document?.system);
  const qualities = asRecord(system?.["qualities"]);
  const qualityValues = asArray(qualities?.["value"]);
  const labels: string[] = [];

  for (const qualityValue of qualityValues) {
    const qualityKey = asRecord(qualityValue)?.["name"];

    if (typeof qualityKey !== "string") {
      continue;
    }

    const woundingType = getWoundingTypeByQualityKey(qualityKey);

    if (!woundingType) {
      continue;
    }

    labels.push(WOUNDING_TYPE_LABELS[woundingType]);
  }

  return labels;
}

export function asItemPropertiesApplication(value: unknown): ItemPropertiesApplication | undefined {
  if (typeof value !== "object" || value === null) {
    return undefined;
  }

  return value;
}

export function asItemPropertyContext(value: unknown): ItemPropertyContext | undefined {
  if (typeof value !== "object" || value === null) {
    return undefined;
  }

  const context = value as ItemPropertyContext;

  if (context.qualities !== undefined && !Array.isArray(context.qualities)) {
    return undefined;
  }

  return context;
}

function supportsWeaponProperties(document: ItemPropertiesApplication["document"]): boolean {
  return (
    document?.type === "weapon" ||
    document?.type === "ammunition" ||
    document?.system?.isWeapon === true
  );
}

function supportsDamagingMagicProperties(document: ItemPropertiesApplication["document"]): boolean {
  return (
    (document?.type === "spell" || document?.type === "prayer") &&
    hasConfiguredDamage(document.system)
  );
}

function hasConfiguredDamage(system: ItemPropertiesDocumentSystem): boolean {
  const damage = asRecord(system?.damage);
  const magicMissile = asRecord(system?.magicMissile);

  return (
    hasMeaningfulValue(damage?.["value"]) ||
    hasMeaningfulValue(damage?.["dice"]) ||
    damage?.["addSL"] === true ||
    magicMissile?.["value"] === true
  );
}

function hasMeaningfulValue(value: unknown): boolean {
  if (typeof value === "number") {
    return value !== 0;
  }

  return typeof value === "string" && value.trim().length > 0;
}

function getWoundingTypeByQualityKey(qualityKey: string): undefined | WoundingType {
  return WOUNDING_TYPES.find(
    (woundingType) => WOUNDING_TYPE_QUALITY_KEYS[woundingType] === qualityKey,
  );
}
