import type { CompendiumPackStatus } from "../../types/module/api/ModuleApi";
import { MODULE_ID } from "../constants";
import { logWarning } from "../logging";

export const CRITICAL_ITEMS_PACK_NAME = "expanded-critical-wounds";
export const CRITICAL_TABLES_PACK_NAME = "expanded-critical-tables";

let tableLookupInstalled = false;

export async function installExpandedCriticalTableLookup(): Promise<void> {
  if (tableLookupInstalled) {
    return;
  }

  const tables = game.wfrp4e?.tables;
  const originalFindTable = tables?.findTable?.bind(tables);

  if (!tables || typeof originalFindTable !== "function") {
    logWarning(`${MODULE_ID} | WFRP table lookup API was unavailable.`);
    return;
  }

  const expandedTables = await getExpandedCriticalTablesByKey();

  if (expandedTables.size === 0) {
    logWarning(`${MODULE_ID} | No expanded critical RollTables were found in the module pack.`);
  }

  tables.findTable = (key: string, column?: unknown) => {
    const originalTable = originalFindTable(key, column);

    if (originalTable) {
      return originalTable;
    }

    return expandedTables.get(key.toLowerCase());
  };

  tableLookupInstalled = true;
}

export async function getExpandedCriticalsCompendiumStatus(): Promise<{
  criticalItems: CompendiumPackStatus;
  criticalTables: CompendiumPackStatus;
}> {
  const criticalItems = await getPackStatus(CRITICAL_ITEMS_PACK_NAME, "Items");
  const criticalTables = await getPackStatus(CRITICAL_TABLES_PACK_NAME, "Tables");

  return { criticalItems, criticalTables };
}

function getPackId(packName: string): string {
  return `${MODULE_ID}.${packName}`;
}

async function getExpandedCriticalTablesByKey(): Promise<Map<string, FoundryDocument>> {
  const tablesByKey = new Map<string, FoundryDocument>();
  const pack = game.packs.get(getPackId(CRITICAL_TABLES_PACK_NAME));

  if (!pack) {
    return tablesByKey;
  }

  const documents = await pack.getDocuments();

  for (const document of documents) {
    const key = document.getFlag("wfrp4e", "key");

    if (typeof key === "string") {
      tablesByKey.set(key.toLowerCase(), document);
    }
  }

  return tablesByKey;
}

async function getPackStatus(
  packName: string,
  fallbackLabel: string,
): Promise<CompendiumPackStatus> {
  const packId = getPackId(packName);
  const pack = game.packs.get(packId);

  if (!pack) {
    return {
      documentCount: 0,
      isAvailable: false,
      label: fallbackLabel,
      packId,
    };
  }

  return {
    documentCount: pack.index?.size ?? (await pack.getDocuments()).length,
    isAvailable: true,
    label: pack.title ?? fallbackLabel,
    packId,
  };
}
