import { setDamageConsoleTargetResult } from "../../../functions/damage-console";

import { getDamageConsoleCard, getDamageConsoleCardUpdate } from "./card-storage";
import { renderDamageConsoleCard } from "./card-renderer";
import { applyDamageConsoleCardTarget } from "./runtime";

const messageQueues = new Map<string, Promise<void>>();

export function installDamageConsoleChatActions(): void {
  Hooks.on("renderChatMessageHTML", (message: unknown, html: unknown) => {
    if (!isFoundryMessage(message) || !(html instanceof HTMLElement)) {
      return;
    }

    const card = getDamageConsoleCard(message);

    if (!card) {
      return;
    }

    const buttons = html.querySelectorAll<HTMLButtonElement>('[data-ech-action="applyDamage"]');

    if (!game.user.isGM) {
      buttons.forEach((button) => button.remove());
      return;
    }

    buttons.forEach((button) => {
      button.addEventListener("click", (event) => {
        event.preventDefault();
        button.disabled = true;
        const targetUuid = button.dataset["targetUuid"];

        if (!targetUuid) {
          return;
        }

        void enqueueDamageApplication(message, targetUuid).catch((error: unknown) => {
          button.disabled = false;
          ui.notifications?.error(getErrorMessage(error));
        });
      });
    });
  });
}

async function enqueueDamageApplication(
  message: FoundryMessage,
  targetUuid: string,
): Promise<void> {
  const previous = messageQueues.get(message.id) ?? Promise.resolve();
  const current = previous
    .catch(() => undefined)
    .then(async () => {
      await applyDamageFromCard(message, targetUuid);
    });

  messageQueues.set(message.id, current);

  try {
    await current;
  } finally {
    if (messageQueues.get(message.id) === current) {
      messageQueues.delete(message.id);
    }
  }
}

async function applyDamageFromCard(message: FoundryMessage, targetUuid: string): Promise<void> {
  const card = getDamageConsoleCard(message);

  if (!card) {
    throw new Error(
      game.i18n.localize("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.cardUnavailable"),
    );
  }

  const target = card.targets.find((candidate) => candidate.uuid === targetUuid);

  if (!target) {
    throw new Error(
      game.i18n.localize(
        "WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.cardTargetUnavailable",
      ),
    );
  }

  if (target.result) {
    throw new Error(
      game.i18n.format("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.alreadyApplied", {
        name: target.name,
      }),
    );
  }

  const result = await applyDamageConsoleCardTarget(card, targetUuid);
  const updatedCard = setDamageConsoleTargetResult(card, targetUuid, result);

  await message.update({
    ...getDamageConsoleCardUpdate(updatedCard),
    content: renderDamageConsoleCard(updatedCard),
  });
}

function isFoundryMessage(value: unknown): value is FoundryMessage {
  return (
    typeof value === "object" &&
    value !== null &&
    typeof (value as Partial<FoundryMessage>).getFlag === "function" &&
    typeof (value as Partial<FoundryMessage>).update === "function"
  );
}

function getErrorMessage(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}
