import { DamageConsoleApplication } from "../../apps/damage-console/DamageConsoleApplication";

import { getTargetedDamageConsoleTargets } from "./targets";

export async function launchDamageConsole(): Promise<void> {
  if (!game.user.isGM) {
    ui.notifications?.warn(
      game.i18n.localize("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.gmOnly"),
    );
    return;
  }

  const targets = getTargetedDamageConsoleTargets();

  if (!targets.length) {
    ui.notifications?.warn(
      game.i18n.localize("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.targetsRequired"),
    );
    return;
  }

  await new DamageConsoleApplication(targets).render(true);
}
