import { registerModuleApi } from "../api/register-module-api";
import { MODULE_ID, WFRP4E_SYSTEM_ID } from "../constants";
import { logDebug, logInfo, logWarning } from "../logging";
import {
  getModuleSettingsDebugSnapshot,
  normalizeStoredMappingSettings,
  registerModuleSettings,
} from "../settings";
import { installExpandedCriticalTableLookup } from "../wfrp4e/critical-compendiums";
import { installCriticalReplacementPatch } from "../wfrp4e/critical-replacement";
import { installDamageConsoleHooks } from "../wfrp4e/damage-console";
import { registerExpandedDamageQualities } from "../wfrp4e/damage-qualities";
import { installNaturalOneCriticalPatch } from "../wfrp4e/natural-one-critical";
import { installWoundingPropertyDisplayHooks } from "../wfrp4e/wounding-properties/display";
import { installZeroWoundCriticalLinkPatch } from "../wfrp4e/zero-wound-critical-links";

export function registerModuleHooks(): void {
  Hooks.once("init", () => {
    logInfo(`${MODULE_ID} | Initializing`);
    registerModuleSettings();
    logDebug(`${MODULE_ID} | init hook running`, {
      foundryVersion: game.version,
      systemId: game.system?.id,
      userIsGM: game.user?.isGM,
    });
    installWoundingPropertyDisplayHooks();
    installDamageConsoleHooks();
    registerExpandedDamageQualities();
  });

  Hooks.once("ready", () => {
    void onReady();
  });
}

async function onReady(): Promise<void> {
  logDebug(`${MODULE_ID} | ready hook running`, {
    foundryVersion: game.version,
    systemId: game.system?.id,
    userIsGM: game.user?.isGM,
    settings: getModuleSettingsDebugSnapshot(),
    wfrpConfigAvailable: Boolean(game.wfrp4e?.config),
    wfrpTablesAvailable: Boolean(game.wfrp4e?.tables),
  });

  if (game.system.id !== WFRP4E_SYSTEM_ID) {
    logWarning(`${MODULE_ID} | Loaded outside ${WFRP4E_SYSTEM_ID}; skipping WFRP integration.`);
    return;
  }

  registerModuleApi();
  await normalizeStoredMappingSettings();
  logDebug(`${MODULE_ID} | ready hook after mapping normalization`, {
    settings: getModuleSettingsDebugSnapshot(),
  });
  registerExpandedDamageQualities();
  await installExpandedCriticalTableLookup();
  installNaturalOneCriticalPatch();
  installCriticalReplacementPatch();
  installZeroWoundCriticalLinkPatch();
  logInfo(`${MODULE_ID} | Ready`);
}
