import { DAMAGE_CATEGORIES, type DamageCategory } from "../../../types/critical-hits";

export type DamageCategoryMappingValue = DamageCategory | "none";
export type DamageCategoryMapping = Record<string, DamageCategoryMappingValue>;

export interface DamageCategoryResolutionInput {
  explicitCategories: readonly DamageCategory[];
  inferFromWeaponProperties: boolean;
  inferFromWeaponTypes: boolean;
  weaponPropertyKeys: readonly string[];
  weaponPropertyMapping: DamageCategoryMapping;
  weaponTypeKeys: readonly string[];
  weaponTypeMapping: DamageCategoryMapping;
}

export interface DamageCategoryResolution {
  categories: DamageCategory[];
  matches: DamageCategoryInferenceMatch[];
  source: "explicit" | "weaponProperty" | "weaponType" | "none";
}

export interface DamageCategoryInferenceMatch {
  category: DamageCategory;
  key: string;
}

