import type { DamageCategory, WoundingType } from "./critical-hits";

export const DAMAGE_CONSOLE_FIXED_HIT_LOCATIONS = [
  "head",
  "lArm",
  "rArm",
  "body",
  "lLeg",
  "rLeg",
] as const;

export const DAMAGE_CONSOLE_HIT_LOCATIONS = [
  "roll",
  ...DAMAGE_CONSOLE_FIXED_HIT_LOCATIONS,
] as const;

export type DamageConsoleFixedHitLocation = (typeof DAMAGE_CONSOLE_FIXED_HIT_LOCATIONS)[number];
export type DamageConsoleHitLocation = (typeof DAMAGE_CONSOLE_HIT_LOCATIONS)[number];

export interface DamageConsoleRequest {
  damageFormula: string;
  hitLocation: DamageConsoleHitLocation;
  ignoreArmour: boolean;
  ignoreToughness: boolean;
  minimumOne: boolean;
  targetUuids: string[];
  woundingType: WoundingType | null;
}

export interface DamageConsoleTargetSnapshot {
  img: string;
  name: string;
  uuid: string;
}

export interface DamageConsoleAppliedResult {
  appliedAt: number;
  appliedBy: string;
  damage: number;
  hitLocation: string;
  html: string;
}

export interface DamageConsoleCardTarget extends DamageConsoleTargetSnapshot {
  result: DamageConsoleAppliedResult | null;
}

export interface DamageConsoleCard {
  damageFormula: string;
  hitLocation: DamageConsoleHitLocation;
  ignoreArmour: boolean;
  ignoreToughness: boolean;
  minimumOne: boolean;
  targets: DamageConsoleCardTarget[];
  version: 1;
  woundingType: WoundingType | null;
}

export type DamageConsoleValidationError =
  | "damageFormulaRequired"
  | "hitLocationInvalid"
  | "targetsRequired"
  | "woundingTypeInvalid";

export interface DamageConsoleCriticalSource {
  category: DamageCategory;
  woundingType: WoundingType;
}
