import { generalizeHitLocation } from "../../functions/critical-hits/table-keys";
import { MODULE_ID } from "../constants";
import { logError } from "../logging";
import { isCriticalReplacementEnabled } from "../settings";

const SOURCE_ITEM_UUID_ATTRIBUTE = "data-ech-source-item-uuid";
const CRITICAL_LOCATION_ATTRIBUTE = "data-ech-critical-location";

let patchInstalled = false;

export function installZeroWoundCriticalLinkPatch(): void {
  if (patchInstalled) {
    return;
  }

  patchApplyDamageLinks();
  document.addEventListener("click", handleAnnotatedCriticalClick, true);
  patchInstalled = true;
}

function patchApplyDamageLinks(): void {
  const actorPrototype = CONFIG.Actor?.documentClass?.prototype;
  const originalApplyDamage = actorPrototype?.applyDamage;

  if (typeof originalApplyDamage !== "function" || !actorPrototype) {
    return;
  }

  actorPrototype.applyDamage = async function (
    this: unknown,
    damage: unknown,
    options: Record<string, unknown> = {},
  ) {
    const result = await originalApplyDamage.call(this, damage, options);
    const sourceItemUuid = getSourceItemUuid(options);

    if (typeof result !== "string" || !sourceItemUuid || !result.includes("critical-roll")) {
      return result;
    }

    return annotateCriticalLinks(result, sourceItemUuid, getCriticalLocation(options));
  };
}

function getSourceItemUuid(options: Record<string, unknown>): string | undefined {
  const sourceTestItem = asRecord(asRecord(options["sourceTest"])?.["item"]);
  const opposedTestItem = asRecord(
    asRecord(asRecord(options["opposedTest"])?.["attackerTest"])?.["item"],
  );
  const sourceItem = asRecord(options["sourceItem"]);
  const uuid = sourceTestItem?.["uuid"] ?? opposedTestItem?.["uuid"] ?? sourceItem?.["uuid"];

  return typeof uuid === "string" ? uuid : undefined;
}

function getCriticalLocation(options: Record<string, unknown>): string | undefined {
  const opposedLocation = asRecord(asRecord(options["opposedTest"])?.["result"])?.["hitloc"];
  const opposedLocationValue = asRecord(opposedLocation)?.["value"];
  const optionLocation = options["loc"];
  let location: string | undefined;

  if (typeof opposedLocationValue === "string") {
    location = opposedLocationValue;
  } else if (typeof optionLocation === "string") {
    location = optionLocation;
  }

  return location && generalizeHitLocation(location) ? location : undefined;
}

function annotateCriticalLinks(
  html: string,
  sourceItemUuid: string,
  criticalLocation: string | undefined,
): string {
  const attributes = [
    `${SOURCE_ITEM_UUID_ATTRIBUTE}="${escapeHtmlAttribute(sourceItemUuid)}"`,
    criticalLocation
      ? `${CRITICAL_LOCATION_ATTRIBUTE}="${escapeHtmlAttribute(criticalLocation)}"`
      : undefined,
  ]
    .filter(Boolean)
    .join(" ");

  return html.replaceAll(
    /<a\b(?![^>]*\bdata-ech-source-item-uuid=)(?=[^>]*\bcritical-roll\b)/g,
    `<a ${attributes}`,
  );
}

function handleAnnotatedCriticalClick(event: MouseEvent): void {
  const eventTarget = event.target;

  if (!(eventTarget instanceof Element) || !isCriticalReplacementEnabled()) {
    return;
  }

  const target = eventTarget.closest(`[data-action="clickTable"][${SOURCE_ITEM_UUID_ATTRIBUTE}]`);

  if (!(target instanceof HTMLElement) || !isCoreCriticalTableKey(target.dataset["table"])) {
    return;
  }

  event.preventDefault();
  event.stopPropagation();
  event.stopImmediatePropagation();

  void rollAnnotatedCritical(target).catch((error: unknown) => {
    reportAnnotatedCriticalFailure(
      "Expanded Critical Hits could not roll an annotated zero-wound critical. See the browser console for details.",
      error,
    );
  });
}

async function rollAnnotatedCritical(target: HTMLElement): Promise<void> {
  const table = target.dataset["table"];
  const formatChatRoll = game.wfrp4e?.tables?.formatChatRoll;

  if (!table || typeof formatChatRoll !== "function") {
    return;
  }

  const messageId = target.closest<HTMLElement>("[data-message-id]")?.dataset["messageId"];
  const modifier = Number.parseInt(target.dataset["modifier"] ?? "0", 10) || 0;
  const html = await formatChatRoll(
    table,
    {
      criticalLocation:
        target.dataset["echCriticalLocation"] ?? getMessageCriticalLocation(messageId),
      messageId,
      modifier,
      showRoll: true,
      sourceItemUuid: target.dataset["echSourceItemUuid"],
    },
    target.dataset["column"],
  );

  if (typeof html !== "string" || html.length === 0) {
    return;
  }

  const chatDataSetup = game.wfrp4e?.utility?.chatDataSetup;
  const chatOptions =
    typeof chatDataSetup === "function"
      ? chatDataSetup("", game.settings.get("core", "rollMode"), true)
      : { content: "" };

  chatOptions["content"] = html;
  await ChatMessage.create(chatOptions);
}

function reportAnnotatedCriticalFailure(message: string, error: unknown): void {
  logError(`${MODULE_ID} | ${message}`, error);
  ui.notifications?.error(message);
}

function getMessageCriticalLocation(messageId: string | undefined): string | undefined {
  if (!messageId) {
    return undefined;
  }

  const message = game.messages.get(messageId);
  const location = asRecord(asRecord(asRecord(message?.system)?.["test"])?.["result"])?.["hitloc"];
  const result = asRecord(location)?.["result"];

  return typeof result === "string" ? result : undefined;
}

function isCoreCriticalTableKey(table: string | undefined): boolean {
  return (
    typeof table === "string" && /^crit(?:head|body|arm|leg|larm|rarm|lleg|rleg)$/i.test(table)
  );
}

function escapeHtmlAttribute(value: string): string {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll('"', "&quot;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;");
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return typeof value === "object" && value !== null
    ? (value as Record<string, unknown>)
    : undefined;
}
