import { DEBUG_CONSOLE_LOGGING_SETTING, MODULE_ID } from "./constants";

export function logDebug(message: string, ...details: unknown[]): void {
  if (!isDebugConsoleLoggingEnabled()) {
    return;
  }

  console.debug(message, ...details);
}

export function logInfo(message: string, ...details: unknown[]): void {
  console.info(message, ...details);
}

export function logWarning(message: string, ...details: unknown[]): void {
  console.warn(message, ...details);
}

export function logError(message: string, ...details: unknown[]): void {
  console.error(message, ...details);
}

function isDebugConsoleLoggingEnabled(): boolean {
  try {
    if (localStorage.getItem(`${MODULE_ID}.debug`) === "true") {
      return true;
    }

    if (!game?.settings?.settings?.has(`${MODULE_ID}.${DEBUG_CONSOLE_LOGGING_SETTING}`)) {
      return false;
    }

    return Boolean(game.settings.get(MODULE_ID, DEBUG_CONSOLE_LOGGING_SETTING));
  } catch {
    return false;
  }
}
