export const WOUNDING_TYPE_TO_DAMAGE_CATEGORY: Record<WoundingType, DamageCategory> = {
  arrows: "arrowsBolts",
  bolts: "arrowsBolts",
  bullets: "bullets",
  claws: "teethClaws",
  crushing: "crushing",
  cutting: "cutting",
  energy: "flameEnergy",
  flame: "flameEnergy",
  piercing: "piercing",
  shot: "shrapnelShot",
  shrapnel: "shrapnelShot",
  sling: "sling",
  teeth: "teethClaws",
  unarmed: "unarmed",
};

const WOUNDING_QUALITY_KEY_TO_CATEGORY = new Map(
  WOUNDING_TYPES.map((type) => [
    WOUNDING_TYPE_QUALITY_KEYS[type],
    WOUNDING_TYPE_TO_DAMAGE_CATEGORY[type],
  ]),
);

const LEGACY_QUALITY_KEY_TO_CATEGORY = new Map(
  DAMAGE_CATEGORIES.map((category) => [LEGACY_DAMAGE_CATEGORY_QUALITY_KEYS[category], category]),
);

export function detectDamageCategories(qualityKeys: Iterable<string>): DamageCategory[] {
  const detectedCategories = new Set<DamageCategory>();

  for (const qualityKey of qualityKeys) {
    const category =
      WOUNDING_QUALITY_KEY_TO_CATEGORY.get(qualityKey) ??
      LEGACY_QUALITY_KEY_TO_CATEGORY.get(qualityKey);

    if (category) {
      detectedCategories.add(category);
    }
  }

  return DAMAGE_CATEGORIES.filter((category) => detectedCategories.has(category));
}

export function chooseDamageCategory(
  categories: readonly DamageCategory[],
  randomValue = Math.random(),
): DamageCategory | undefined {
  if (categories.length === 0) {
    return undefined;
  }

  const index = Math.min(Math.floor(randomValue * categories.length), categories.length - 1);

  return categories[index];
}
