import { WOUNDING_TYPE_TO_DAMAGE_CATEGORY } from "../critical-hits/damage-categories";
import {
  DAMAGE_CONSOLE_HIT_LOCATIONS,
  type DamageConsoleAppliedResult,
  type DamageConsoleCard,
  type DamageConsoleCardTarget,
  type DamageConsoleCriticalSource,
  type DamageConsoleRequest,
  type DamageConsoleTargetSnapshot,
} from "../../types/damage-console";
import { WOUNDING_TYPES } from "../../types/critical-hits";

import { normalizeDamageConsoleRequest } from "./request";

export function createDamageConsoleCard(
  request: DamageConsoleRequest,
  targets: readonly DamageConsoleTargetSnapshot[],
): DamageConsoleCard {
  const normalized = normalizeDamageConsoleRequest(request);
  const targetsByUuid = new Map(targets.map((target) => [target.uuid, target]));

  return {
    damageFormula: normalized.damageFormula,
    hitLocation: normalized.hitLocation,
    ignoreArmour: normalized.ignoreArmour,
    ignoreToughness: normalized.ignoreToughness,
    minimumOne: normalized.minimumOne,
    targets: normalized.targetUuids.map((uuid) => {
      const target = targetsByUuid.get(uuid);

      if (!target) {
        throw new Error(`Damage console target ${uuid} could not be resolved.`);
      }

      return { ...target, result: null };
    }),
    version: 1,
    woundingType: normalized.woundingType,
  };
}

export function setDamageConsoleTargetResult(
  card: DamageConsoleCard,
  targetUuid: string,
  result: DamageConsoleAppliedResult,
): DamageConsoleCard {
  let matched = false;
  const targets = card.targets.map((target) => {
    if (target.uuid !== targetUuid) {
      return target;
    }

    matched = true;

    if (target.result) {
      throw new Error(`Damage has already been applied to ${target.name}.`);
    }

    return { ...target, result };
  });

  if (!matched) {
    throw new Error(`Damage console target ${targetUuid} is not part of this card.`);
  }

  return { ...card, targets };
}

export function getDamageConsoleCriticalSource(
  card: DamageConsoleCard,
): DamageConsoleCriticalSource | undefined {
  if (!card.woundingType) {
    return undefined;
  }

  return {
    category: WOUNDING_TYPE_TO_DAMAGE_CATEGORY[card.woundingType],
    woundingType: card.woundingType,
  };
}

export function parseDamageConsoleCard(value: unknown): DamageConsoleCard | undefined {
  const card = asRecord(value);

  if (
    card?.["version"] !== 1 ||
    typeof card["damageFormula"] !== "string" ||
    !isHitLocation(card["hitLocation"]) ||
    typeof card["ignoreArmour"] !== "boolean" ||
    typeof card["ignoreToughness"] !== "boolean" ||
    typeof card["minimumOne"] !== "boolean" ||
    !isWoundingTypeOrNull(card["woundingType"]) ||
    !Array.isArray(card["targets"])
  ) {
    return undefined;
  }

  const targets = card["targets"].map(parseTarget);

  if (targets.some((target) => !target)) {
    return undefined;
  }

  return {
    damageFormula: card["damageFormula"],
    hitLocation: card["hitLocation"],
    ignoreArmour: card["ignoreArmour"],
    ignoreToughness: card["ignoreToughness"],
    minimumOne: card["minimumOne"],
    targets: targets as DamageConsoleCardTarget[],
    version: 1,
    woundingType: card["woundingType"],
  };
}

function parseTarget(value: unknown): DamageConsoleCardTarget | undefined {
  const target = asRecord(value);

  if (
    typeof target?.["uuid"] !== "string" ||
    typeof target["name"] !== "string" ||
    typeof target["img"] !== "string"
  ) {
    return undefined;
  }

  const result = target["result"] === null ? null : parseResult(target["result"]);

  if (result === undefined) {
    return undefined;
  }

  return { img: target["img"], name: target["name"], result, uuid: target["uuid"] };
}

function parseResult(value: unknown): DamageConsoleAppliedResult | undefined {
  const result = asRecord(value);

  if (
    typeof result?.["appliedAt"] !== "number" ||
    typeof result["appliedBy"] !== "string" ||
    typeof result["damage"] !== "number" ||
    typeof result["hitLocation"] !== "string" ||
    typeof result["html"] !== "string"
  ) {
    return undefined;
  }

  return {
    appliedAt: result["appliedAt"],
    appliedBy: result["appliedBy"],
    damage: result["damage"],
    hitLocation: result["hitLocation"],
    html: result["html"],
  };
}

function isHitLocation(value: unknown): value is DamageConsoleCard["hitLocation"] {
  return (
    typeof value === "string" &&
    DAMAGE_CONSOLE_HIT_LOCATIONS.includes(value as DamageConsoleCard["hitLocation"])
  );
}

function isWoundingTypeOrNull(value: unknown): value is DamageConsoleCard["woundingType"] {
  return (
    value === null ||
    (typeof value === "string" &&
      WOUNDING_TYPES.includes(value as DamageConsoleCard["woundingType"] & string))
  );
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return typeof value === "object" && value !== null
    ? (value as Record<string, unknown>)
    : undefined;
}
