import { chooseDamageCategory } from "../../functions/critical-hits";
import {
  generalizeHitLocation,
  getExpandedCriticalTableKey,
  getRulesetVariant,
} from "../../functions/critical-hits/table-keys";
import { MODULE_ID } from "../constants";
import { logDebug } from "../logging";
import {
  isCriticalReplacementEnabled,
  isWeaponPropertyDamageInferenceEnabled,
  isWeaponTypeDamageInferenceEnabled,
} from "../settings";
import { summarizeCriticalOptions, summarizeSourceItem } from "./critical-replacement/debug";
import { reportExpandedCriticalFailure } from "./critical-replacement/failure";
import { prepareCriticalItemForPosting } from "./critical-replacement/item-posting";
import { resolveItemDamageCategories } from "./damage-category-resolution";
import { getDamageConsoleCategoryForMessage } from "./damage-console/card-storage";

let replacementInstalled = false;

export function installCriticalReplacementPatch(): void {
  if (replacementInstalled) {
    logDebug(`${MODULE_ID} | Critical replacement patch already installed.`);
    return;
  }

  const tables = game.wfrp4e?.tables;

  if (
    !tables ||
    typeof tables.findTable !== "function" ||
    typeof tables.formatChatRoll !== "function"
  ) {
    logDebug(`${MODULE_ID} | Critical replacement patch skipped: WFRP table API unavailable`, {
      hasTables: Boolean(tables),
      hasFindTable: typeof tables?.findTable === "function",
      hasFormatChatRoll: typeof tables?.formatChatRoll === "function",
    });
    return;
  }

  const findTable = tables.findTable.bind(tables);
  const originalFormatChatRoll = tables.formatChatRoll.bind(tables);

  tables.formatChatRoll = async (table: string, options = {}, column = null) => {
    const isCoreCritical = isCoreCriticalTableKey(table);

    if (!isCriticalReplacementEnabled() || !isCoreCritical) {
      if (isCoreCritical) {
        logDebug(`${MODULE_ID} | Critical replacement fallthrough`, {
          table,
          reason: "replacement disabled",
          options: summarizeCriticalOptions(options),
        });
      }

      return originalFormatChatRoll(table, options, column);
    }

    const location = getCriticalLocation(table, options);
    const damageConsoleSource = getDamageConsoleCategoryForMessage(options["messageId"]);
    let sourceItem: unknown;
    let categoryClues: unknown;
    let categoryResolution: unknown;
    let category = damageConsoleSource?.category;

    logDebug(`${MODULE_ID} | Critical replacement inspecting WFRP critical roll`, {
      table,
      location,
      options: summarizeCriticalOptions(options),
    });

    if (!category) {
      try {
        sourceItem = await getSourceItem(options);
      } catch (error) {
        return reportExpandedCriticalFailure(
          `Expanded Critical Hits could not resolve the critical source item. See the browser console for details.`,
          table,
          error,
        );
      }

      const itemResolution = resolveItemDamageCategories(sourceItem);
      categoryClues = itemResolution.clues;
      categoryResolution = itemResolution.resolution;
      category = chooseDamageCategory(itemResolution.resolution.categories);
    }

    logDebug(`${MODULE_ID} | Critical replacement damage category resolution`, {
      table,
      location,
      sourceItem: summarizeSourceItem(sourceItem),
      categoryClues,
      categoryResolution,
      chosenCategory: category,
      damageConsoleSource,
      inferFromWeaponProperties: isWeaponPropertyDamageInferenceEnabled(),
      inferFromWeaponTypes: isWeaponTypeDamageInferenceEnabled(),
    });

    if (!location || !category) {
      logDebug(`${MODULE_ID} | Critical replacement fallthrough`, {
        table,
        reason: !location ? "location unavailable" : "damage category unavailable",
      });
      return originalFormatChatRoll(table, options, column);
    }

    const ruleset = getRulesetVariant(Boolean(game.settings.get("wfrp4e", "uiaCrits")));
    const expandedTableKey = getExpandedCriticalTableKey(ruleset, category, location);

    if (!findTable(expandedTableKey)) {
      return reportExpandedCriticalFailure(
        `Expanded Critical Hits table ${expandedTableKey} is missing from the module compendium.`,
        expandedTableKey,
      );
    }

    logDebug(`${MODULE_ID} | Critical replacement rolling expanded table`, {
      table,
      expandedTableKey,
      ruleset,
      category,
      location,
    });

    try {
      const expandedResult = await formatExpandedCriticalChatRoll(
        expandedTableKey,
        options,
        column,
      );

      if (expandedResult !== undefined) {
        return expandedResult;
      }
    } catch (error) {
      return reportExpandedCriticalFailure(
        `Expanded Critical Hits could not roll ${expandedTableKey}. See the browser console for details.`,
        expandedTableKey,
        error,
      );
    }

    return reportExpandedCriticalFailure(
      `Expanded Critical Hits could not use WFRP's RollTable API for ${expandedTableKey}.`,
      expandedTableKey,
    );
  };

  replacementInstalled = true;
  logDebug(`${MODULE_ID} | Critical replacement patch installed.`);
}

async function formatExpandedCriticalChatRoll(
  table: string,
  options: Record<string, unknown>,
  column: unknown,
): Promise<unknown> {
  const rollTable = game.wfrp4e?.tables?.rollTable;

  if (typeof rollTable !== "function") {
    return undefined;
  }

  const result = await rollTable.call(game.wfrp4e.tables, table, options, column);

  if (await postExpandedCriticalItem(result, options)) {
    return null;
  }

  const resultData = asRecord(result);

  if (options["returnResult"]) {
    return result;
  }

  return resultData?.["result"];
}

async function postExpandedCriticalItem(
  result: unknown,
  options: Record<string, unknown>,
): Promise<boolean> {
  const resultData = asRecord(result);
  const resultObject = asRecord(resultData?.["object"]);
  const documentUuid = resultObject?.["documentUuid"];

  if (typeof documentUuid !== "string") {
    logDebug(`${MODULE_ID} | Expanded critical result had no document UUID`, { result });
    return false;
  }

  const document = await fromUuid(documentUuid);
  const item = prepareCriticalItemForPosting(document, options);

  if (!item) {
    throw new Error(`Could not resolve expanded critical item ${documentUuid}.`);
  }

  logDebug(`${MODULE_ID} | Posting expanded critical item`, {
    documentUuid,
    messageId: options["messageId"],
    criticalLocation: options["criticalLocation"],
  });
  await item.postItem(undefined, {
    "flags.wfrp4e.sourceMessageId": options["messageId"],
  });

  return true;
}

function getCriticalLocation(table: string, options: Record<string, unknown>) {
  const optionLocation = options["criticalLocation"];

  if (typeof optionLocation === "string") {
    return generalizeHitLocation(optionLocation);
  }

  return generalizeHitLocation(table.replace(/^crit/i, ""));
}

async function getSourceItem(options: Record<string, unknown>): Promise<unknown> {
  const sourceItemUuid = options["sourceItemUuid"];

  if (typeof sourceItemUuid === "string") {
    return await fromUuid(sourceItemUuid);
  }

  const messageId = options["messageId"];

  if (typeof messageId !== "string") {
    return undefined;
  }

  const message = game.messages.get(messageId);
  const system = asRecord(message?.system);
  const test = asRecord(system?.["test"]);
  const preData = asRecord(test?.["preData"]);

  return test?.["item"] ?? test?.["weapon"] ?? preData?.["item"];
}

function isCoreCriticalTableKey(table: string): boolean {
  return /^crit(?:head|body|arm|leg|larm|rarm|lleg|rleg)$/i.test(table);
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return typeof value === "object" && value !== null
    ? (value as Record<string, unknown>)
    : undefined;
}
