import { WOUNDING_TYPE_LABELS } from "../../../functions/critical-hits/damage-categories";
import type { DamageConsoleCard } from "../../../types/damage-console";

export function renderDamageConsoleCard(card: DamageConsoleCard): string {
  const typeLabel = card.woundingType
    ? WOUNDING_TYPE_LABELS[card.woundingType]
    : localize("damageConsole.unspecified");
  const reductionLabels = [
    card.ignoreArmour ? localize("damageConsole.ignoreArmour") : undefined,
    card.ignoreToughness ? localize("damageConsole.ignoreToughness") : undefined,
  ].filter((label): label is string => Boolean(label));
  const reduction = reductionLabels.length
    ? reductionLabels.join(", ")
    : localize("damageConsole.none");

  return `<div class="wfrp4e chat-card ech-damage-console-card">
    <h3><i class="fa-solid fa-bolt"></i> ${escapeHtml(localize("damageConsole.cardTitle"))}</h3>
    <dl class="ech-damage-console-card__summary">
      ${summaryRow(localize("damageConsole.damage"), card.damageFormula)}
      ${summaryRow(localize("damageConsole.hitLocation"), locationLabel(card.hitLocation))}
      ${summaryRow(localize("damageConsole.woundingType"), typeLabel)}
      ${summaryRow(localize("damageConsole.ignores"), reduction)}
      ${summaryRow(localize("damageConsole.minimumOne"), yesNo(card.minimumOne))}
    </dl>
    <div class="ech-damage-console-card__targets">
      ${card.targets.map(renderTarget).join("")}
    </div>
  </div>`;
}

function renderTarget(target: DamageConsoleCard["targets"][number]): string {
  const identity = `<div class="ech-damage-console-card__identity">
    <img src="${escapeAttribute(target.img)}" alt="" />
    <strong>${escapeHtml(target.name)}</strong>
  </div>`;

  if (!target.result) {
    return `<section class="ech-damage-console-card__target">
      ${identity}
      <button type="button" class="chat-button chat-button-gm ech-damage-console-card__apply"
        data-ech-action="applyDamage" data-target-uuid="${escapeAttribute(target.uuid)}">
        <i class="fa-solid fa-bolt"></i> ${escapeHtml(localize("damageConsole.applyDamage"))}
      </button>
    </section>`;
  }

  return `<section class="ech-damage-console-card__target ech-damage-console-card__target--applied">
    ${identity}
    <p class="ech-damage-console-card__roll">
      ${escapeHtml(localize("damageConsole.rolled"))}: <strong>${target.result.damage}</strong>
      &middot; ${escapeHtml(locationLabel(target.result.hitLocation))}
    </p>
    <div class="ech-damage-console-card__result">${target.result.html}</div>
  </section>`;
}

function summaryRow(label: string, value: string): string {
  return `<div><dt>${escapeHtml(label)}</dt><dd>${escapeHtml(value)}</dd></div>`;
}

function locationLabel(location: string): string {
  if (location === "roll") {
    return game.i18n.localize("Roll");
  }

  const localizationKey = game.wfrp4e?.config?.locations?.[location];

  return localizationKey ? game.i18n.localize(localizationKey) : location;
}

function yesNo(value: boolean): string {
  return localize(value ? "damageConsole.yes" : "damageConsole.no");
}

function localize(key: string): string {
  return game.i18n.localize(`WFRP4E_EXPANDED_CRITICAL_HITS.${key}`);
}

function escapeHtml(value: string): string {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function escapeAttribute(value: string): string {
  return escapeHtml(value);
}
