import type { Component } from "vue";

import { WOUNDING_TYPE_LABELS } from "../../../functions/critical-hits/damage-categories";
import type {
  DamageConsoleHitLocation,
  DamageConsoleRequest,
  DamageConsoleTargetSnapshot,
} from "../../../types/damage-console";
import { DAMAGE_CONSOLE_HIT_LOCATIONS } from "../../../types/damage-console";
import { WOUNDING_TYPES, type WoundingType } from "../../../types/critical-hits";
import DamageConsoleApp from "../../../view/apps/damage-console/DamageConsoleApp.vue";
import type {
  DamageConsoleAppProps,
  DamageConsoleOption,
} from "../../../view/apps/damage-console/types";
import { MODULE_ID } from "../../constants";
import { postDamageConsoleCard } from "../../wfrp4e/damage-console/posting";
import { FoundryVueApplication } from "../FoundryVueApplication";

const HIT_LOCATION_LOCALIZATION_KEYS: Record<DamageConsoleHitLocation, string> = {
  body: "Body",
  head: "Head",
  lArm: "Left Arm",
  lLeg: "Left Leg",
  rArm: "Right Arm",
  rLeg: "Right Leg",
  roll: "Roll",
};

export class DamageConsoleApplication extends FoundryVueApplication {
  static override DEFAULT_OPTIONS = {
    id: `${MODULE_ID}-damage-console`,
    position: {
      height: "auto",
      width: 620,
    },
    tag: "section",
    window: {
      icon: "fa-solid fa-bolt",
      resizable: true,
      title: "WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.title",
    },
  };

  readonly #targets: DamageConsoleTargetSnapshot[];

  constructor(targets: DamageConsoleTargetSnapshot[]) {
    super();
    this.#targets = targets;
  }

  protected override getVueComponent(): Component {
    return DamageConsoleApp;
  }

  protected override getVueProps(): DamageConsoleAppProps {
    return {
      hitLocationOptions: createHitLocationOptions(),
      localize: (key) => game.i18n.localize(key),
      onCancel: () => void this.close(),
      onPost: async (request: DamageConsoleRequest) => {
        await postDamageConsoleCard(request);
        await this.close();
      },
      targets: this.#targets,
      woundingTypeOptions: createWoundingTypeOptions(),
    };
  }
}

function createHitLocationOptions(): DamageConsoleOption<DamageConsoleHitLocation>[] {
  return DAMAGE_CONSOLE_HIT_LOCATIONS.map((value) => ({
    label: game.i18n.localize(HIT_LOCATION_LOCALIZATION_KEYS[value]),
    value,
  }));
}

function createWoundingTypeOptions(): DamageConsoleOption<WoundingType | null>[] {
  return [
    {
      label: game.i18n.localize("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.unspecified"),
      value: null,
    },
    ...WOUNDING_TYPES.map((value) => ({ label: WOUNDING_TYPE_LABELS[value], value })),
  ];
}
