import { launchDamageConsole } from "./launch";

interface SceneControlButtons {
  tokens?: {
    tools?: Record<string, unknown>;
  };
}

export function installDamageConsoleSceneControl(): void {
  Hooks.on("getSceneControlButtons", (buttons: unknown) => {
    const tokenTools = (buttons as SceneControlButtons | undefined)?.tokens?.tools;

    if (!tokenTools) {
      return;
    }

    tokenTools["expandedCriticalDamageConsole"] = {
      button: true,
      icon: "fa-solid fa-bolt",
      name: "expandedCriticalDamageConsole",
      onClick: () => void launchDamageConsole(),
      title: "WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.sceneControl",
      visible: game.user.isGM,
    };
  });
}
