import {
  DAMAGE_CONSOLE_HIT_LOCATIONS,
  type DamageConsoleRequest,
  type DamageConsoleValidationError,
} from "../../types/damage-console";
import { WOUNDING_TYPES } from "../../types/critical-hits";

export function normalizeDamageConsoleRequest(request: DamageConsoleRequest): DamageConsoleRequest {
  return {
    ...request,
    damageFormula: request.damageFormula.trim(),
    targetUuids: [...new Set(request.targetUuids.map((uuid) => uuid.trim()).filter(Boolean))],
  };
}

export function validateDamageConsoleRequest(
  request: DamageConsoleRequest,
): DamageConsoleValidationError[] {
  const errors: DamageConsoleValidationError[] = [];

  if (!request.damageFormula.trim()) {
    errors.push("damageFormulaRequired");
  }

  if (!DAMAGE_CONSOLE_HIT_LOCATIONS.includes(request.hitLocation)) {
    errors.push("hitLocationInvalid");
  }

  if (request.targetUuids.every((uuid) => !uuid.trim())) {
    errors.push("targetsRequired");
  }

  if (request.woundingType !== null && !WOUNDING_TYPES.includes(request.woundingType)) {
    errors.push("woundingTypeInvalid");
  }

  return errors;
}
