import { defineStore } from "pinia";
import { ref } from "vue";

import {
  normalizeDamageConsoleRequest,
  validateDamageConsoleRequest,
} from "../../functions/damage-console";
import type {
  DamageConsoleHitLocation,
  DamageConsoleRequest,
  DamageConsoleTargetSnapshot,
  DamageConsoleValidationError,
} from "../../types/damage-console";
import type { WoundingType } from "../../types/critical-hits";

type PostDamageConsoleCard = (request: DamageConsoleRequest) => Promise<void>;

export const useDamageConsoleStore = defineStore("damageConsole", () => {
  const damageFormula = ref("1d10");
  const hitLocation = ref<DamageConsoleHitLocation>("roll");
  const ignoreArmour = ref(false);
  const ignoreToughness = ref(false);
  const isPosting = ref(false);
  const minimumOne = ref(true);
  const runtimeError = ref("");
  const targets = ref<DamageConsoleTargetSnapshot[]>([]);
  const validationErrors = ref<DamageConsoleValidationError[]>([]);
  const woundingType = ref<WoundingType | null>(null);
  let postCard: PostDamageConsoleCard | undefined;

  function initialize(
    nextTargets: DamageConsoleTargetSnapshot[],
    nextPostCard: PostDamageConsoleCard,
  ): void {
    targets.value = nextTargets;
    postCard = nextPostCard;
  }

  async function submit(): Promise<void> {
    if (!postCard || isPosting.value) {
      return;
    }

    runtimeError.value = "";
    const request = normalizeDamageConsoleRequest({
      damageFormula: damageFormula.value,
      hitLocation: hitLocation.value,
      ignoreArmour: ignoreArmour.value,
      ignoreToughness: ignoreToughness.value,
      minimumOne: minimumOne.value,
      targetUuids: targets.value.map((target) => target.uuid),
      woundingType: woundingType.value,
    });
    validationErrors.value = validateDamageConsoleRequest(request);

    if (validationErrors.value.length) {
      return;
    }

    isPosting.value = true;

    try {
      await postCard(request);
    } catch (error) {
      runtimeError.value = error instanceof Error ? error.message : String(error);
    } finally {
      isPosting.value = false;
    }
  }

  return {
    damageFormula,
    hitLocation,
    ignoreArmour,
    ignoreToughness,
    initialize,
    isPosting,
    minimumOne,
    runtimeError,
    submit,
    targets,
    validationErrors,
    woundingType,
  };
});
