import type { CriticalRollPatchStatus } from "../../types/module/api/CriticalRollPatchStatus";
import { isSuccessfulNaturalOne } from "../../functions/critical-hits";
import { MODULE_ID } from "../constants";
import { logWarning } from "../logging";
import { isNaturalOneCriticalsEnabled } from "../settings";

const PATCHED = Symbol.for(`${MODULE_ID}.naturalOneCriticalPatch`);

type CriticalFumbleResult = "critical" | "fumble" | "";
type PatchKey = "isCriticalFumble" | "computeProperties";
type PatchFlags = Partial<Record<PatchKey, true>>;

let patchStatus: CriticalRollPatchStatus = {
  installed: false,
  message: "Natural 1 critical patch has not run.",
};

export function getNaturalOneCriticalPatchStatus(): CriticalRollPatchStatus {
  return { ...patchStatus };
}

export function installNaturalOneCriticalPatch(): void {
  const rolls = game.wfrp4e?.rolls;

  if (!rolls?.TestWFRP) {
    setPatchStatus(false, "WFRP4e roll classes were not available.");
    return;
  }

  const patchedGetter = patchCriticalFumbleGetter(rolls.TestWFRP);
  const patchedAttacks = patchAttackCriticals([rolls.WeaponTest, rolls.TraitTest]);

  patchStatus = {
    installed: patchedGetter,
    message: patchedGetter
      ? `Natural 1 critical patch installed. Attack wrappers installed: ${patchedAttacks}.`
      : "TestWFRP.isCriticalFumble could not be patched.",
  };

  if (!patchedGetter) {
    logWarning(`${MODULE_ID} | ${patchStatus.message}`);
  }
}

function patchCriticalFumbleGetter(TestWFRP: WfrpTestConstructor): boolean {
  const prototype = TestWFRP.prototype;

  if (getPatched(prototype).isCriticalFumble) {
    return true;
  }

  const descriptor = Object.getOwnPropertyDescriptor(prototype, "isCriticalFumble");

  if (!descriptor?.get) {
    return false;
  }

  Object.defineProperty(prototype, "isCriticalFumble", {
    configurable: descriptor.configurable,
    enumerable: descriptor.enumerable,
    get(this: WfrpTest) {
      if (isNaturalOneCritical(this)) {
        return "critical";
      }

      return descriptor.get?.call(this) as CriticalFumbleResult;
    },
  });

  markPatched(prototype, "isCriticalFumble");
  return true;
}

function patchAttackCriticals(testClasses: Array<WfrpAttackTestConstructor | undefined>): number {
  let patchedCount = 0;

  for (const TestClass of testClasses) {
    const prototype = TestClass?.prototype;

    if (!prototype || getPatched(prototype).computeProperties) {
      continue;
    }

    const computeProperties = prototype.computeProperties;

    if (!computeProperties) {
      continue;
    }

    prototype.computeProperties = function patchedComputeProperties(
      this: WfrpTest,
      ...args: unknown[]
    ) {
      if (isNaturalOneCritical(this)) {
        setCriticalResult(this);
      }

      const result = computeProperties.apply(this, args);

      if (isNaturalOneCritical(this)) {
        setCriticalResult(this);
      }

      return result;
    };

    markPatched(prototype, "computeProperties");
    patchedCount += 1;
  }

  return patchedCount;
}

function isNaturalOneCritical(test: WfrpTest): boolean {
  return (
    isNaturalOneCriticalsEnabled() &&
    isSuccessfulNaturalOne({
      roll: test.result?.roll,
      target: test.result?.target,
    })
  );
}

function setCriticalResult(test: WfrpTest): void {
  if (!test.result) {
    return;
  }

  test.result.color_green = true;
  test.result.critical ||= game.i18n.localize("Critical");
}

function markPatched(prototype: object, key: PatchKey): void {
  const patched = getPatched(prototype);
  patched[key] = true;

  Object.defineProperty(prototype, PATCHED, {
    configurable: true,
    value: patched,
  });
}

function getPatched(prototype: object): PatchFlags {
  if (Object.prototype.hasOwnProperty.call(prototype, PATCHED)) {
    return Reflect.get(prototype, PATCHED) as PatchFlags;
  }

  return {};
}

function setPatchStatus(installed: boolean, message: string): void {
  patchStatus = { installed, message };
  logWarning(`${MODULE_ID} | ${message}`);
}

interface WfrpTestConstructor {
  prototype: WfrpTestPrototype;
}

interface WfrpAttackTestConstructor {
  prototype: WfrpAttackTestPrototype;
}

interface WfrpTestPrototype {
  readonly isCriticalFumble: CriticalFumbleResult;
}

interface WfrpAttackTestPrototype {
  computeProperties?: (this: WfrpTest, ...args: unknown[]) => unknown;
}

interface WfrpTest {
  result?: {
    roll?: unknown;
    target?: unknown;
    color_green?: boolean;
    critical?: string;
  };
}
