import type { ItemPropertiesApplication } from "./types";

export function getConstructorName(value: unknown): string | undefined {
  if (typeof value !== "object" || value === null) {
    return undefined;
  }

  return value.constructor?.name;
}

export function summarizeDocument(
  document: ItemPropertiesApplication["document"],
): Record<string, unknown> | undefined {
  if (!document) {
    return undefined;
  }

  return {
    id: document.id,
    name: document.name,
    type: document.type,
    uuid: document.uuid,
  };
}
