import type { ItemPropertiesApplication, ItemPropertiesDocument } from "./types";

import { WOUNDING_SECTION_CLASS } from "./support";

const CONFIGURE_PROPERTIES_SELECTOR = `.${WOUNDING_SECTION_CLASS}__sheet-row a[data-ech-action="configureProperties"]`;

interface WfrpApplications {
  apps?: {
    ItemProperties?: unknown;
  };
}

type ItemPropertiesConstructor = new (itemDocument: ItemPropertiesDocument) => {
  render(force?: boolean): unknown;
};

const itemPropertiesOpeners = new Map<string, (itemDocument: ItemPropertiesDocument) => void>();

let sheetActionHandlersInstalled = false;

export function installWoundingSheetActionHandlers(): void {
  if (sheetActionHandlersInstalled) {
    return;
  }

  document.addEventListener("click", handleConfigurePropertiesClick, true);
  sheetActionHandlersInstalled = true;
}

export function getItemDocumentUuid(
  itemDocument: ItemPropertiesApplication["document"],
): string | undefined {
  return itemDocument?.uuid;
}

export function registerItemPropertiesOpener(
  itemUuid: string,
  opener: (itemDocument: ItemPropertiesDocument) => void,
): void {
  itemPropertiesOpeners.set(itemUuid, opener);
}

export function openItemPropertiesDialog(
  itemDocument: ItemPropertiesApplication["document"],
): void {
  const ItemProperties = getItemPropertiesConstructor();

  if (!itemDocument || !ItemProperties) {
    return;
  }

  new ItemProperties(itemDocument).render(true);
}

function handleConfigurePropertiesClick(event: MouseEvent): void {
  const action = getConfigurePropertiesAction(event.target);

  if (!action) {
    return;
  }

  event.preventDefault();
  event.stopPropagation();
  void openItemPropertiesDialogFromAction(action);
}

function getConfigurePropertiesAction(target: EventTarget | null): HTMLAnchorElement | undefined {
  if (!(target instanceof Element)) {
    return undefined;
  }

  const action = target.closest<HTMLAnchorElement>(CONFIGURE_PROPERTIES_SELECTOR);

  return action ?? undefined;
}

async function openItemPropertiesDialogFromAction(action: HTMLAnchorElement): Promise<void> {
  const itemUuid = action.closest<HTMLElement>(`.${WOUNDING_SECTION_CLASS}__sheet-row`)?.dataset[
    "echItemUuid"
  ];

  if (!itemUuid) {
    return;
  }

  const itemDocument = await fromUuid(itemUuid);

  if (!isItemPropertiesDocument(itemDocument)) {
    return;
  }

  const registeredOpener = itemPropertiesOpeners.get(itemUuid);

  if (registeredOpener) {
    registeredOpener(itemDocument);
    return;
  }

  openItemPropertiesDialog(itemDocument);
}

function getItemPropertiesConstructor(): ItemPropertiesConstructor | undefined {
  const wfrpApplications = game.wfrp4e as undefined | WfrpApplications;
  const ItemProperties = wfrpApplications?.apps?.ItemProperties;

  if (!isItemPropertiesConstructor(ItemProperties)) {
    return undefined;
  }

  return ItemProperties;
}

function isItemPropertiesConstructor(value: unknown): value is ItemPropertiesConstructor {
  return typeof value === "function";
}

function isItemPropertiesDocument(value: unknown): value is ItemPropertiesDocument {
  return typeof value === "object" && value !== null;
}
