import {
  resolveDamageCategories,
  type DamageCategoryResolution,
} from "../../functions/critical-hits";
import {
  getWeaponPropertyDamageMapping,
  getWeaponTypeDamageMapping,
  isWeaponPropertyDamageInferenceEnabled,
  isWeaponTypeDamageInferenceEnabled,
} from "../settings";
import { getDamageCategoryCluesFromItem, type DamageCategoryClues } from "./quality-extraction";

export interface ItemDamageCategoryResolution {
  clues: DamageCategoryClues;
  resolution: DamageCategoryResolution;
}

export function resolveItemDamageCategories(item: unknown): ItemDamageCategoryResolution {
  const clues = getDamageCategoryCluesFromItem(item);
  const resolution = resolveDamageCategories({
    ...clues,
    inferFromWeaponProperties: isWeaponPropertyDamageInferenceEnabled(),
    inferFromWeaponTypes: isWeaponTypeDamageInferenceEnabled(),
    weaponPropertyMapping: getWeaponPropertyDamageMapping(),
    weaponTypeMapping: getWeaponTypeDamageMapping(),
  });

  return { clues, resolution };
}
