import {
  createDamageConsoleCard,
  normalizeDamageConsoleRequest,
  validateDamageConsoleRequest,
} from "../../../functions/damage-console";
import type { DamageConsoleRequest } from "../../../types/damage-console";

import { addDamageConsoleCardFlag } from "./card-storage";
import { renderDamageConsoleCard } from "./card-renderer";
import { resolveDamageConsoleTarget } from "./targets";

export async function postDamageConsoleCard(
  request: DamageConsoleRequest,
): Promise<string | undefined> {
  assertGameMaster();
  const normalized = normalizeDamageConsoleRequest(request);
  const validationErrors = validateDamageConsoleRequest(normalized);

  if (validationErrors.length) {
    throw new Error(
      game.i18n.localize(
        `WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.validation.${validationErrors[0]}`,
      ),
    );
  }

  const targets = await Promise.all(
    normalized.targetUuids.map(async (uuid) => (await resolveDamageConsoleTarget(uuid)).snapshot),
  );
  const card = createDamageConsoleCard(normalized, targets);
  const content = renderDamageConsoleCard(card);
  const messageData = game.wfrp4e?.utility?.chatDataSetup?.(content) ?? { content };

  addDamageConsoleCardFlag(messageData, card);
  const message = await ChatMessage.create(messageData);

  return message?.id;
}

function assertGameMaster(): void {
  if (!game.user.isGM) {
    throw new Error(
      game.i18n.localize("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.gmOnly"),
    );
  }
}
