import type {
  DamageCategory,
  GeneralizedHitLocation,
  RulesetVariant,
} from "../../types/critical-hits";

export function getExpandedCriticalTableKey(
  ruleset: RulesetVariant,
  category: DamageCategory,
  location: GeneralizedHitLocation,
): string {
  return `ech-crit-${ruleset}-${category}-${location}`.toLowerCase();
}

export function generalizeHitLocation(location: string): GeneralizedHitLocation | undefined {
  const normalizedLocation = location.toLowerCase();

  if (normalizedLocation === "head" || normalizedLocation === "body") {
    return normalizedLocation;
  }

  if (normalizedLocation.endsWith("arm")) {
    return "arm";
  }

  if (normalizedLocation.endsWith("leg")) {
    return "leg";
  }

  return undefined;
}

export function getRulesetVariant(useUpInArmsCriticals: boolean): RulesetVariant {
  return useUpInArmsCriticals ? "upInArms" : "core";
}
