export function summarizeCriticalOptions(
  options: Record<string, unknown>,
): Record<string, unknown> {
  return {
    criticalLocation: options["criticalLocation"],
    messageId: options["messageId"],
    returnResult: options["returnResult"],
    sourceItemUuid: options["sourceItemUuid"],
  };
}

export function summarizeSourceItem(sourceItem: unknown): Record<string, unknown> | undefined {
  const item = asRecord(sourceItem);

  if (!item) {
    return undefined;
  }

  return {
    id: item["id"],
    name: item["name"],
    type: item["type"],
    uuid: item["uuid"],
  };
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return typeof value === "object" && value !== null
    ? (value as Record<string, unknown>)
    : undefined;
}
