import {
  getDamageConsoleCriticalSource,
  parseDamageConsoleCard,
} from "../../../functions/damage-console";
import type { DamageConsoleCard } from "../../../types/damage-console";
import { MODULE_ID } from "../../constants";

export const DAMAGE_CONSOLE_FLAG = "damageConsole";

export function getDamageConsoleCard(message: FoundryMessage): DamageConsoleCard | undefined {
  return parseDamageConsoleCard(message.getFlag(MODULE_ID, DAMAGE_CONSOLE_FLAG));
}

export function getDamageConsoleCategoryForMessage(
  messageId: unknown,
): ReturnType<typeof getDamageConsoleCriticalSource> {
  if (typeof messageId !== "string") {
    return undefined;
  }

  const message = game.messages.get(messageId);
  const card = message ? getDamageConsoleCard(message) : undefined;

  return card ? getDamageConsoleCriticalSource(card) : undefined;
}

export function addDamageConsoleCardFlag(
  data: Record<string, unknown>,
  card: DamageConsoleCard,
): void {
  const flags = asRecord(data["flags"]) ?? {};
  const moduleFlags = asRecord(flags[MODULE_ID]) ?? {};

  data["flags"] = {
    ...flags,
    [MODULE_ID]: {
      ...moduleFlags,
      [DAMAGE_CONSOLE_FLAG]: card,
    },
  };
}

export function getDamageConsoleCardUpdate(card: DamageConsoleCard): Record<string, unknown> {
  return {
    [`flags.${MODULE_ID}.${DAMAGE_CONSOLE_FLAG}`]: card,
  };
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return typeof value === "object" && value !== null
    ? (value as Record<string, unknown>)
    : undefined;
}
