import type { DamageConsoleTargetSnapshot } from "../../../types/damage-console";

export interface RuntimeActor {
  applyBasicDamage: (damage: number, options: Record<string, unknown>) => Promise<unknown>;
  details?: {
    hitLocationTable?: {
      value?: unknown;
    };
  };
  system?: {
    details?: {
      hitLocationTable?: {
        value?: unknown;
      };
    };
  };
}

interface RuntimeTokenDocument {
  actor?: unknown;
  name?: unknown;
  texture?: {
    src?: unknown;
  };
  uuid?: unknown;
}

interface RuntimeToken {
  actor?: unknown;
  document?: RuntimeTokenDocument;
  name?: unknown;
  texture?: {
    src?: unknown;
  };
}

export function getTargetedDamageConsoleTargets(): DamageConsoleTargetSnapshot[] {
  const snapshots = [...game.user.targets]
    .map(toTargetSnapshot)
    .filter((target): target is DamageConsoleTargetSnapshot => Boolean(target));

  return [...new Map(snapshots.map((target) => [target.uuid, target])).values()];
}

export async function resolveDamageConsoleTarget(
  uuid: string,
): Promise<{ actor: RuntimeActor; snapshot: DamageConsoleTargetSnapshot }> {
  const document = (await fromUuid(uuid)) as RuntimeTokenDocument | undefined;
  const actor = document?.actor ?? document;

  if (!isRuntimeActor(actor)) {
    throw new Error(
      game.i18n.format("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.targetUnavailable", {
        uuid,
      }),
    );
  }

  return {
    actor,
    snapshot: {
      img: getString(document?.texture?.src) ?? "icons/svg/mystery-man.svg",
      name: getString(document?.name) ?? uuid,
      uuid,
    },
  };
}

function toTargetSnapshot(value: unknown): DamageConsoleTargetSnapshot | undefined {
  const token = value as RuntimeToken | undefined;
  const document = token?.document;
  const uuid = getString(document?.uuid);

  if (!uuid || !isRuntimeActor(document?.actor ?? token?.actor)) {
    return undefined;
  }

  return {
    img:
      getString(document?.texture?.src) ??
      getString(token?.texture?.src) ??
      "icons/svg/mystery-man.svg",
    name: getString(token?.name) ?? getString(document?.name) ?? uuid,
    uuid,
  };
}

function isRuntimeActor(value: unknown): value is RuntimeActor {
  return (
    typeof value === "object" &&
    value !== null &&
    typeof (value as Partial<RuntimeActor>).applyBasicDamage === "function"
  );
}

function getString(value: unknown): string | undefined {
  return typeof value === "string" && value ? value : undefined;
}
