import type {
  DamageCategory,
  DamageCategoryInferenceMatch,
  DamageCategoryResolution,
} from "../../../functions/critical-hits";

import {
  DAMAGE_CATEGORY_LABELS,
  normalizeInferenceKey,
  WOUNDING_TYPE_LABELS,
} from "../../../functions/critical-hits";
import { MODULE_ID } from "../../constants";
import { logDebug } from "../../logging";
import { resolveItemDamageCategories } from "../damage-category-resolution";
import { asRecord } from "../runtime-values";

const observedTrappingsTabs = new WeakSet<HTMLElement>();

export function styleRenderedActorWoundingProperties(application: unknown, element: unknown): void {
  if (!(element instanceof HTMLElement)) {
    return;
  }

  const combatTab = findRenderedTab(element, "combat");
  const trappingsTab = findRenderedTab(element, "trappings");

  if (combatTab) {
    styleExplicitCombatDamageTypes(combatTab);
    decorateInferredCombatDamageTypes(application, combatTab);
  }

  if (!trappingsTab) {
    return;
  }

  refreshTrappingsDamageTypes(application, trappingsTab);

  if (observedTrappingsTabs.has(trappingsTab)) {
    return;
  }

  const observer = new MutationObserver(() => {
    refreshTrappingsDamageTypes(application, trappingsTab);
  });
  observer.observe(trappingsTab, { childList: true, subtree: true });
  observedTrappingsTabs.add(trappingsTab);
}

function findRenderedTab(element: HTMLElement, tabId: string): HTMLElement | undefined {
  if (element.matches(`section[data-tab="${tabId}"]`)) {
    return element;
  }

  return element.querySelector<HTMLElement>(`section[data-tab="${tabId}"]`) ?? undefined;
}

function styleExplicitCombatDamageTypes(combatTab: HTMLElement): void {
  const woundingLabels = new Set(Object.values(WOUNDING_TYPE_LABELS));
  const propertyLinks = combatTab.querySelectorAll<HTMLAnchorElement>(
    '.item-property-row a[data-action="itemPropertyDropdown"][data-type="qualities"]',
  );

  for (const propertyLink of propertyLinks) {
    if (woundingLabels.has(propertyLink.textContent.trim())) {
      propertyLink.classList.add("ech-wounding-property-combat-text");
    }
  }
}

function decorateInferredCombatDamageTypes(application: unknown, combatTab: HTMLElement): void {
  const propertyRows = combatTab.querySelectorAll<HTMLElement>(
    '.list-row[data-uuid] .item-property-row:not([data-ech-inference-checked="true"])',
  );

  for (const propertyRow of propertyRows) {
    propertyRow.dataset.echInferenceChecked = "true";
    const resolution = resolveRowDamageCategories(application, propertyRow);

    if (!isInferredResolution(resolution)) {
      continue;
    }

    for (const category of resolution.categories) {
      propertyRow.append(createInferredDamageTypeLabel("combat", category, resolution));
    }
  }
}

function refreshTrappingsDamageTypes(application: unknown, trappingsTab: HTMLElement): void {
  styleExplicitTrappingsDamageTypes(trappingsTab);
  decorateInferredTrappingsDamageTypes(application, trappingsTab);
}

function styleExplicitTrappingsDamageTypes(trappingsTab: HTMLElement): void {
  const woundingLabels = new Set(Object.values(WOUNDING_TYPE_LABELS));
  const propertyTags = trappingsTab.querySelectorAll<HTMLElement>(
    ".tags .tag:not(.ech-inferred-damage-type)",
  );

  for (const propertyTag of propertyTags) {
    if (woundingLabels.has(propertyTag.textContent.trim())) {
      propertyTag.classList.add("ech-wounding-property-trappings-badge");
    }
  }
}

function decorateInferredTrappingsDamageTypes(
  application: unknown,
  trappingsTab: HTMLElement,
): void {
  const tagGroups = trappingsTab.querySelectorAll<HTMLElement>(
    '.list-row[data-uuid] .tags:not([data-ech-inference-checked="true"])',
  );

  for (const tags of tagGroups) {
    tags.dataset.echInferenceChecked = "true";
    const resolution = resolveRowDamageCategories(application, tags);

    if (!isInferredResolution(resolution)) {
      continue;
    }

    for (const category of resolution.categories) {
      tags.append(createInferredDamageTypeLabel("trappings", category, resolution));
    }
  }
}

function resolveRowDamageCategories(
  application: unknown,
  element: HTMLElement,
): DamageCategoryResolution | undefined {
  const uuid = element.closest<HTMLElement>(".list-row[data-uuid]")?.dataset.uuid;

  if (!uuid) {
    return undefined;
  }

  try {
    const item = getEmbeddedItemFromActorSheet(application, uuid);

    if (!supportsActorSheetDamageTypeDisplay(item)) {
      logDebug(
        `${MODULE_ID} | Inferred damage display skipped for ${uuid}: item unavailable or unsupported.`,
      );
      return undefined;
    }

    const resolution = resolveItemDamageCategories(item).resolution;
    logDebug(
      `${MODULE_ID} | Inferred damage display resolved ${uuid}: source=${resolution.source} categories=${resolution.categories.join(",") || "none"}`,
    );

    return resolution;
  } catch (error) {
    logDebug(`${MODULE_ID} | Could not display inferred damage type`, { error, uuid });
    return undefined;
  }
}

function getEmbeddedItemFromActorSheet(application: unknown, uuid: string): unknown {
  const sheet = asRecord(application);
  const actor = asRecord(sheet?.["actor"]) ?? asRecord(sheet?.["document"]);
  const items = asRecord(actor?.["items"]);
  const getItem = items?.["get"];
  const itemId = uuid.split(".").at(-1);

  if (typeof getItem !== "function" || !itemId) {
    return undefined;
  }

  return getItem.call(items, itemId);
}

function supportsActorSheetDamageTypeDisplay(item: unknown): boolean {
  const itemRecord = asRecord(item);
  const system = asRecord(itemRecord?.["system"]);

  return (
    itemRecord?.["type"] === "weapon" ||
    itemRecord?.["type"] === "ammunition" ||
    system?.["isWeapon"] === true
  );
}

function isInferredResolution(
  resolution: DamageCategoryResolution | undefined,
): resolution is DamageCategoryResolution & { source: "weaponProperty" | "weaponType" } {
  return resolution?.source === "weaponProperty" || resolution?.source === "weaponType";
}

function createInferredDamageTypeLabel(
  location: "combat" | "trappings",
  category: DamageCategory,
  resolution: DamageCategoryResolution & { source: "weaponProperty" | "weaponType" },
): HTMLElement {
  const label = document.createElement(location === "combat" ? "span" : "div");
  const tooltip = createInferenceTooltip(category, resolution.source, resolution.matches);

  label.classList.add("ech-inferred-damage-type", `ech-inferred-damage-type--${location}`);
  if (location === "trappings") {
    label.classList.add("tag");
  }
  label.dataset.echDamageCategory = category;
  label.dataset.tooltip = tooltip;
  label.setAttribute("aria-label", tooltip);
  label.textContent = DAMAGE_CATEGORY_LABELS[category];

  return label;
}

function createInferenceTooltip(
  category: DamageCategory,
  source: "weaponProperty" | "weaponType",
  matches: readonly DamageCategoryInferenceMatch[],
): string {
  const sourceKeys = matches
    .filter((match) => match.category === category)
    .map((match) => formatInferenceKey(match.key, source));
  const sourceLabel = source === "weaponProperty" ? "item property" : "weapon type";

  return sourceKeys.length > 0
    ? `Inferred from ${sourceKeys.join(", ")}`
    : `Inferred from ${sourceLabel}`;
}

function formatInferenceKey(key: string, source: "weaponProperty" | "weaponType"): string {
  if (source === "weaponProperty") {
    const qualityLabels = game.wfrp4e?.utility?.qualityList?.() ?? {};
    const normalizedKey = normalizeInferenceKey(key);

    for (const [qualityKey, label] of Object.entries(qualityLabels)) {
      if (
        normalizeInferenceKey(qualityKey) === normalizedKey ||
        normalizeInferenceKey(label) === normalizedKey
      ) {
        return label;
      }
    }
  }

  const words = key
    .replaceAll(/([a-z])([A-Z])/g, "$1 $2")
    .replaceAll(/[_-]+/g, " ")
    .trim();

  return words.replaceAll(/\b\w/g, (character) => character.toUpperCase());
}
