import { installDamageConsoleChatActions } from "./chat-actions";
import { installDamageConsoleSceneControl } from "./scene-controls";

export { getDamageConsoleCategoryForMessage } from "./card-storage";
export { launchDamageConsole } from "./launch";
export { postDamageConsoleCard } from "./posting";

let hooksInstalled = false;

export function installDamageConsoleHooks(): void {
  if (hooksInstalled) {
    return;
  }

  installDamageConsoleChatActions();
  installDamageConsoleSceneControl();
  hooksInstalled = true;
}
