import {
  WOUNDING_TYPE_LABELS,
  WOUNDING_TYPE_QUALITY_KEYS,
} from "../../../functions/critical-hits/damage-categories";
import { WOUNDING_TYPES } from "../../../types/critical-hits";
import { MODULE_ID } from "../../constants";
import { logDebug } from "../../logging";
import { installWoundingSheetActionHandlers } from "./actions";
import { styleRenderedActorWoundingProperties } from "./actor-sheet";
import { groupRenderedWoundingProperties, splitRenderedItemSheetWoundingProperties } from "./sheet";
import {
  appendWoundingLabels,
  asItemPropertiesApplication,
  asItemPropertyContext,
  supportsDamageTypeProperties,
} from "./support";

export { appendWoundingLabels } from "./support";

let itemPropertiesHooksInstalled = false;
const ITEM_PROPERTIES_CONTEXT_PATCHED = Symbol.for(`${MODULE_ID}.woundingPropertiesContextPatched`);

interface ItemPropertiesPrototype {
  _prepareContext?: (...args: unknown[]) => Promise<unknown>;
}

interface ItemPropertiesConstructor {
  prototype?: ItemPropertiesPrototype;
}

interface WfrpApplications {
  apps?: {
    ItemProperties?: unknown;
  };
}

export function installWoundingPropertyDisplayHooks(): void {
  installWoundingSheetActionHandlers();
  installItemPropertiesContextPatch();

  if (itemPropertiesHooksInstalled) {
    logDebug(`${MODULE_ID} | Wounding property display hooks already installed.`);
    return;
  }

  Hooks.on("renderItemProperties", (_application, element) => {
    groupRenderedWoundingProperties(element);
  });

  Hooks.on("renderApplicationV2", (application, element) => {
    splitRenderedItemSheetWoundingProperties(application, element);
    styleRenderedActorWoundingProperties(application, element);

    if (hasActorDocument(application)) {
      styleCommittedActorSheet(application);
    }
  });

  Hooks.on("renderBaseWFRP4eActorSheet", (application, element) => {
    styleRenderedActorWoundingProperties(application, element);
    styleCommittedActorSheet(application);
  });

  itemPropertiesHooksInstalled = true;
  logDebug(`${MODULE_ID} | Wounding property display hooks installed.`);
}

function styleCommittedActorSheet(application: unknown, remainingFrames = 5): void {
  if (typeof application !== "object" || application === null) {
    return;
  }

  requestAnimationFrame(() => {
    const element = (application as { element?: unknown }).element;

    if (element instanceof HTMLElement && element.isConnected) {
      logDebug(
        `${MODULE_ID} | Styling committed WFRP actor sheet with ${element.querySelectorAll(".item-property-row").length} property rows.`,
      );
      styleRenderedActorWoundingProperties(application, element);
      return;
    }

    if (remainingFrames > 1) {
      styleCommittedActorSheet(application, remainingFrames - 1);
      return;
    }

    logDebug(`${MODULE_ID} | Committed WFRP actor sheet element was unavailable.`);
  });
}

function hasActorDocument(application: unknown): boolean {
  if (typeof application !== "object" || application === null) {
    return false;
  }

  const actor = (application as { actor?: unknown }).actor;
  return typeof actor === "object" && actor !== null;
}

function installItemPropertiesContextPatch(): void {
  const ItemProperties = getItemPropertiesConstructor();
  const prototype = ItemProperties?.prototype;
  const originalPrepareContext = prototype?._prepareContext;

  if (!prototype || !originalPrepareContext) {
    logDebug(`${MODULE_ID} | ItemProperties context patch skipped: application unavailable.`);
    return;
  }

  if (isItemPropertiesContextPatched(originalPrepareContext)) {
    logDebug(`${MODULE_ID} | ItemProperties context patch already installed.`);
    return;
  }

  const patchedPrepareContext = async function prepareWoundingPropertyContext(
    this: ItemPropertiesApplication,
    ...args: unknown[]
  ): Promise<unknown> {
    const document = this.document;

    if (supportsDamageTypeProperties(document)) {
      this.qualities = appendWoundingLabels(this.qualities ?? {});
    }

    const context = await originalPrepareContext.apply(this, args);
    appendWoundingPropertiesToContext(this, context);

    return context;
  };

  Object.defineProperty(patchedPrepareContext, ITEM_PROPERTIES_CONTEXT_PATCHED, {
    value: true,
  });
  prototype._prepareContext = patchedPrepareContext;
  logDebug(`${MODULE_ID} | ItemProperties context patch installed.`);
}

function getItemPropertiesConstructor(): ItemPropertiesConstructor | undefined {
  const wfrpApplications = game.wfrp4e as undefined | WfrpApplications;
  const ItemProperties = wfrpApplications?.apps?.ItemProperties;

  return typeof ItemProperties === "function"
    ? (ItemProperties as ItemPropertiesConstructor)
    : undefined;
}

function isItemPropertiesContextPatched(
  prepareContext: (...args: unknown[]) => Promise<unknown>,
): boolean {
  return Boolean(
    (prepareContext as typeof prepareContext & Record<PropertyKey, unknown>)[
      ITEM_PROPERTIES_CONTEXT_PATCHED
    ],
  );
}

function appendWoundingPropertiesToContext(application: unknown, context: unknown): void {
  const itemProperties = asItemPropertiesApplication(application);
  const renderContext = asItemPropertyContext(context);
  const document = itemProperties?.document;

  if (!itemProperties || !renderContext || !supportsDamageTypeProperties(document)) {
    logDebug(`${MODULE_ID} | Skipping ItemProperties damage type context append`, {
      applicationName: getConstructorName(application),
      hasItemProperties: Boolean(itemProperties),
      hasRenderContext: Boolean(renderContext),
      document: summarizeDocument(document),
      supportsDamageTypeProperties: supportsDamageTypeProperties(document),
    });
    return;
  }

  logDebug(`${MODULE_ID} | Appending damage types to ItemProperties context`, {
    applicationName: getConstructorName(application),
    document: summarizeDocument(document),
    originalQualityCount: Object.keys(itemProperties.qualities ?? {}).length,
    renderedQualityCount: renderContext.qualities?.length ?? 0,
  });
  itemProperties.qualities = appendWoundingLabels(itemProperties.qualities ?? {});
  renderContext.qualities ??= [];

  for (const woundingType of WOUNDING_TYPES) {
    const qualityKey = WOUNDING_TYPE_QUALITY_KEYS[woundingType];

    if (renderContext.qualities.some((quality) => quality.key === qualityKey)) {
      continue;
    }

    renderContext.qualities.push({
      existing: itemProperties.document?.originalProperties?.qualities?.[qualityKey],
      hasValue: false,
      key: qualityKey,
      name: WOUNDING_TYPE_LABELS[woundingType],
    });
  }

  logDebug(`${MODULE_ID} | ItemProperties context after damage type append`, {
    document: summarizeDocument(document),
    renderedQualityCount: renderContext.qualities.length,
  });
}

function getConstructorName(value: unknown): string | undefined {
  if (typeof value !== "object" || value === null) {
    return undefined;
  }

  return value.constructor?.name;
}

function summarizeDocument(document: unknown): Record<string, unknown> | undefined {
  if (typeof document !== "object" || document === null) {
    return undefined;
  }

  const item = document as {
    id?: string;
    name?: string;
    type?: string;
    uuid?: string;
  };

  return {
    id: item.id,
    name: item.name,
    type: item.type,
    uuid: item.uuid,
  };
}
