<script setup lang="ts">
import { useDamageConsoleStore } from "../../../state/damage-console";
import type { DamageConsoleAppProps } from "./types";

const props = defineProps<DamageConsoleAppProps>();
const store = useDamageConsoleStore();

store.initialize(props.targets, props.onPost);

function text(key: string): string {
  return props.localize(`WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.${key}`);
}
</script>

<template>
  <!-- eslint-disable vue/html-self-closing -- Prettier formats Vue template void elements with self-closing syntax. -->
  <form
    class="tw:flex tw:flex-col tw:gap-4 tw:rounded-box tw:bg-base-100 tw:p-4 tw:text-base-content"
    @submit.prevent="store.submit"
  >
    <div
      v-if="store.validationErrors.length || store.runtimeError"
      role="alert"
      class="tw:dui-alert tw:dui-alert-error tw:text-sm"
    >
      <i class="fa-solid fa-triangle-exclamation" aria-hidden="true" />
      <div>
        <p v-for="error in store.validationErrors" :key="error">
          {{ text(`validation.${error}`) }}
        </p>
        <p v-if="store.runtimeError">{{ store.runtimeError }}</p>
      </div>
    </div>

    <section class="tw:dui-card tw:dui-card-border tw:dui-card-sm">
      <div class="tw:dui-card-body">
        <h2 class="tw:dui-card-title tw:text-base">
          <i class="fa-solid fa-crosshairs" aria-hidden="true" />
          {{ text("targets") }}
        </h2>
        <div class="tw:grid tw:grid-cols-1 tw:gap-2 tw:sm:grid-cols-2">
          <div
            v-for="target in store.targets"
            :key="target.uuid"
            class="tw:flex tw:min-w-0 tw:items-center tw:gap-2 tw:rounded-sm tw:bg-base-200 tw:p-2"
          >
            <img :src="target.img" alt="" class="tw:h-9 tw:w-9 tw:rounded-sm tw:object-cover" />
            <strong class="tw:min-w-0 tw:truncate">{{ target.name }}</strong>
          </div>
        </div>
      </div>
    </section>

    <div class="tw:grid tw:grid-cols-1 tw:gap-4 tw:md:grid-cols-2">
      <fieldset
        class="tw:dui-fieldset tw:min-w-0 tw:rounded-box tw:border tw:border-base-300 tw:p-4"
      >
        <legend class="tw:dui-fieldset-legend">{{ text("damageDetails") }}</legend>

        <label class="tw:dui-label" for="ech-damage-formula">{{ text("damage") }}</label>
        <input
          id="ech-damage-formula"
          v-model="store.damageFormula"
          class="tw:dui-input tw:w-full"
          name="damageFormula"
          placeholder="1d10"
          required
          type="text"
        />
        <p class="tw:dui-label tw:whitespace-normal">{{ text("damageHint") }}</p>

        <label class="tw:dui-label" for="ech-hit-location">{{ text("hitLocation") }}</label>
        <select
          id="ech-hit-location"
          v-model="store.hitLocation"
          class="tw:dui-select tw:w-full"
          name="hitLocation"
        >
          <option
            v-for="option in props.hitLocationOptions"
            :key="option.value"
            :value="option.value"
          >
            {{ option.label }}
          </option>
        </select>

        <label class="tw:dui-label" for="ech-wounding-type">{{ text("woundingType") }}</label>
        <select
          id="ech-wounding-type"
          v-model="store.woundingType"
          class="tw:dui-select tw:w-full"
          name="woundingType"
        >
          <option
            v-for="option in props.woundingTypeOptions"
            :key="option.value ?? 'unspecified'"
            :value="option.value"
          >
            {{ option.label }}
          </option>
        </select>
        <p class="tw:dui-label tw:whitespace-normal">{{ text("woundingTypeHint") }}</p>
      </fieldset>

      <fieldset
        class="tw:dui-fieldset tw:min-w-0 tw:rounded-box tw:border tw:border-base-300 tw:p-4"
      >
        <legend class="tw:dui-fieldset-legend">{{ text("damageOptions") }}</legend>

        <label
          class="tw:dui-label tw:cursor-pointer tw:justify-between tw:gap-4 tw:whitespace-normal"
        >
          <span>{{ text("ignoreToughness") }}</span>
          <input
            v-model="store.ignoreToughness"
            class="tw:dui-checkbox"
            name="ignoreToughness"
            type="checkbox"
          />
        </label>

        <label
          class="tw:dui-label tw:cursor-pointer tw:justify-between tw:gap-4 tw:whitespace-normal"
        >
          <span>{{ text("ignoreArmour") }}</span>
          <input
            v-model="store.ignoreArmour"
            class="tw:dui-checkbox"
            name="ignoreArmour"
            type="checkbox"
          />
        </label>

        <label
          class="tw:dui-label tw:cursor-pointer tw:justify-between tw:gap-4 tw:whitespace-normal"
        >
          <span>{{ text("minimumOne") }}</span>
          <input
            v-model="store.minimumOne"
            class="tw:dui-checkbox"
            name="minimumOne"
            type="checkbox"
          />
        </label>

        <div role="alert" class="tw:dui-alert tw:mt-2 tw:text-sm">
          <i class="fa-solid fa-circle-info" aria-hidden="true" />
          <span>{{ text("postHint") }}</span>
        </div>
      </fieldset>
    </div>

    <div class="tw:flex tw:justify-end tw:gap-2">
      <button class="tw:dui-btn" type="button" :disabled="store.isPosting" @click="props.onCancel">
        {{ text("cancel") }}
      </button>
      <button class="tw:dui-btn tw:dui-btn-primary" type="submit" :disabled="store.isPosting">
        <i
          :class="store.isPosting ? 'fa-solid fa-spinner fa-spin' : 'fa-solid fa-message'"
          aria-hidden="true"
        />
        {{ text("post") }}
      </button>
    </div>
  </form>
</template>
