import type { DamageConsoleAppliedResult, DamageConsoleCard } from "../../../types/damage-console";

import { resolveDamageConsoleTarget, type RuntimeActor } from "./targets";

export async function applyDamageConsoleCardTarget(
  card: DamageConsoleCard,
  targetUuid: string,
): Promise<DamageConsoleAppliedResult> {
  const { actor } = await resolveDamageConsoleTarget(targetUuid);
  const damage = await evaluateDamage(card.damageFormula);
  const hitLocation = await resolveHitLocation(card, actor);
  const damageType = resolveDamageType(card.ignoreArmour, card.ignoreToughness);
  const result = await actor.applyBasicDamage(damage, {
    damageType,
    loc: hitLocation,
    minimumOne: card.minimumOne,
    suppressMsg: true,
  });

  if (typeof result !== "string" || !result) {
    throw new Error(
      game.i18n.localize("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.damageNotApplied"),
    );
  }

  return {
    appliedAt: Date.now(),
    appliedBy: game.user.name,
    damage,
    hitLocation,
    html: result,
  };
}

async function evaluateDamage(formula: string): Promise<number> {
  try {
    const roll = await new Roll(formula).evaluate();
    const total = Number(roll.total);

    if (!Number.isInteger(total) || total < 0) {
      throw new Error("Damage must resolve to a non-negative whole number.");
    }

    return total;
  } catch (error) {
    throw new Error(
      game.i18n.format("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.invalidFormula", {
        formula,
      }),
      { cause: error },
    );
  }
}

async function resolveHitLocation(card: DamageConsoleCard, actor: RuntimeActor): Promise<string> {
  if (card.hitLocation !== "roll") {
    return card.hitLocation;
  }

  const tableKey =
    getString(actor.details?.hitLocationTable?.value) ??
    getString(actor.system?.details?.hitLocationTable?.value) ??
    "hitloc";
  const result = await game.wfrp4e?.tables?.rollTable?.(tableKey, { hideDSN: true });
  const location = getString(asRecord(result)?.["result"]);

  if (!location) {
    throw new Error(
      game.i18n.localize("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.hitLocationFailed"),
    );
  }

  return location;
}

function resolveDamageType(ignoreArmour: boolean, ignoreToughness: boolean): unknown {
  const damageTypes = game.wfrp4e?.config?.DAMAGE_TYPE;

  if (!damageTypes) {
    throw new Error(
      game.i18n.localize("WFRP4E_EXPANDED_CRITICAL_HITS.damageConsole.errors.damageApiUnavailable"),
    );
  }

  if (ignoreArmour && ignoreToughness) {
    return damageTypes.IGNORE_ALL;
  }

  if (ignoreArmour) {
    return damageTypes.IGNORE_AP;
  }

  if (ignoreToughness) {
    return damageTypes.IGNORE_TB;
  }

  return damageTypes.NORMAL;
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return typeof value === "object" && value !== null
    ? (value as Record<string, unknown>)
    : undefined;
}

function getString(value: unknown): string | undefined {
  return typeof value === "string" && value ? value : undefined;
}
